mapper.sql:
FROM tb_monitoring_event me LEFT JOIN tb_user u ON u.user_id = me.user_id WHERE 1 = 1
AND me.created_at >= #{request.startDate}
AND me.created_at < DATE_ADD(#{request.endDate}, INTERVAL 1 DAY)
AND me.resolved_yn = #{request.resolvedYn}
AND me.event_type = #{request.eventType}
AND me.severity = #{request.severity}
AND ( me.event_code LIKE CONCAT('%', #{request.keyword}, '%') OR me.title LIKE CONCAT('%', #{request.keyword}, '%') OR me.message LIKE CONCAT('%', #{request.keyword}, '%') OR me.request_uri LIKE CONCAT('%', #{request.keyword}, '%') OR me.trace_id LIKE CONCAT('%', #{request.keyword}, '%') OR me.exception_class LIKE CONCAT('%', #{request.keyword}, '%') )

mapper.update:
UPDATE tb_monitoring_event SET resolved_yn = #{resolvedYn}, resolved_at =
NOW() NULL , resolved_by =
#{resolvedBy} NULL , updated_at = NOW() WHERE event_id = #{eventId}
